class Solution:
    def minimumOperations(self, grid) -> int:
        m, n = len(grid), len(grid[0])
        INF = float('inf')
        # cost[j][d] = number of cells in column j != d
        cost = []
        for j in range(n):
            freq = [0] * 10
            for i in range(m):
                freq[grid[i][j]] += 1
            cost.append([m - freq[d] for d in range(10)])
        # dp[d] = min ops for previous column assigned digit d
        dp = cost[0][:]
        for j in range(1, n):
            new_dp = [INF] * 10
            best = min(dp)
            for d in range(10):
                for d2 in range(10):
                    if d2 != d:
                        new_dp[d] = min(new_dp[d], dp[d2] + cost[j][d])
            dp = new_dp
        return min(dp)

