class Solution:
    def minimumOperations(self, grid) -> int:
        m, n = len(grid), len(grid[0])
        # cost[j][d]: cells in col j that are not d
        cost = []
        for j in range(n):
            freq = [0] * 10
            for i in range(m):
                freq[grid[i][j]] += 1
            cost.append([m - freq[d] for d in range(10)])
        # DP: track best and second-best of previous column
        prev = cost[0][:]
        for j in range(1, n):
            # find the best and second best in prev
            first_val, second_val = float('inf'), float('inf')
            first_d = -1
            for d, v in enumerate(prev):
                if v < first_val:
                    second_val = first_val
                    first_val = v
                    first_d = d
                elif v < second_val:
                    second_val = v
            curr = [0] * 10
            for d in range(10):
                best_prev = first_val if d != first_d else second_val
                curr[d] = best_prev + cost[j][d]
            prev = curr
        return min(prev)

