var minimumOperations = function(grid) {
    const m = grid.length, n = grid[0].length;
    const cost = [];
    for (let j = 0; j < n; j++) {
        const freq = new Array(10).fill(0);
        for (let i = 0; i < m; i++) freq[grid[i][j]]++;
        cost.push(Array.from({length:10}, (_, d) => m - freq[d]));
    }
    let prev = cost[0].slice();
    for (let j = 1; j < n; j++) {
        let fv = Infinity, sv = Infinity, fd = -1;
        for (let d = 0; d < 10; d++) {
            if (prev[d] < fv) { sv = fv; fv = prev[d]; fd = d; }
            else if (prev[d] < sv) sv = prev[d];
        }
        const curr = new Array(10);
        for (let d = 0; d < 10; d++) {
            const bestPrev = d !== fd ? fv : sv;
            curr[d] = bestPrev + cost[j][d];
        }
        prev = curr;
    }
    return Math.min(...prev);
};
